window.questionsDb = [
  // 1. DBMS Concepts (40 Qs)
  { topic: "database", question: "What is the primary purpose of a Database Management System (DBMS)?", options: ["To store data in a physical file only", "To provide an environment that is both convenient and efficient to use in retrieving and storing database information", "To allow users to access the hardware directly", "To provide a programming language for web development"], answer: 1, explanation: "DBMS acts as an interface between the user and the database for efficient data management." },
  { topic: "database", question: "In the ANSI/SPARC three-level architecture, which level describes how the data is stored in the database?", options: ["External level", "Conceptual level", "Internal level", "Logical level"], answer: 2, explanation: "The internal level defines the physical storage structure of the database." },
  { topic: "database", question: "Which of the following describes 'Logical Data Independence'?", options: ["The ability to change the internal schema without affecting the conceptual schema", "The ability to change the conceptual schema without having to change external schemas", "The ability to change physical storage without affecting users", "The ability to change the OS without affecting the database"], answer: 1, explanation: "Logical data independence is the capacity to change the conceptual schema without changing external schemas or application programs." },
  { topic: "database", question: "A 'Database Schema' is defined as:", options: ["The actual data stored in the database", "The overall design or structure of the database", "A snapshot of the data at a point in time", "The physical hardware running the DBMS"], answer: 1, explanation: "Schema is the logical structure or blueprint of the database." },
  { topic: "database", question: "Which data model represents data as a collection of tables (relations)?", options: ["Hierarchical Model", "Network Model", "Relational Model", "Object-Oriented Model"], answer: 2, explanation: "The relational model organizes data into tables consisting of rows and columns." },
  { topic: "database", question: "In a Hierarchical Model, records are organized in a:", options: ["Graph structure", "Tree structure", "Relational structure", "Linear structure"], answer: 1, explanation: "The hierarchical model uses a parent-child relationship in a tree-like structure." },
  { topic: "database", question: "Which of the following is an advantage of a DBMS over a traditional file-processing system?", options: ["Data Redundancy", "Data Inconsistency", "Data Isolation", "Data Sharing and Centralized Control"], answer: 3, explanation: "DBMS allows multiple users to share data and provides centralized control for security and integrity." },
  { topic: "database", question: "The 'Metadata' in a database is also known as:", options: ["Data Dictionary", "Data Snapshot", "Data Instance", "Data Tuple"], answer: 0, explanation: "The data dictionary contains metadata, which is 'data about data'." },
  { topic: "database", question: "Which level of abstraction is closest to the users?", options: ["Physical Level", "Conceptual Level", "View Level", "Internal Level"], answer: 2, explanation: "The view level (or external level) is the highest level of abstraction that describes only part of the entire database for specific user groups." },
  { topic: "database", question: "The process of managing multiple versions of the database schema is called:", options: ["Schema Versioning", "Schema Evolution", "Schema Migration", "Schema Refactoring"], answer: 1, explanation: "Schema evolution refers to the ability of the database to change over time." },
  { topic: "database", question: "Who is responsible for authorizing access to the database, coordinating and monitoring its use?", options: ["Database Designer", "End User", "Database Administrator (DBA)", "System Analyst"], answer: 2, explanation: "The DBA manages the database, ensures security, and monitors performance." },
  { topic: "database", question: "Which of the following is NOT a property of the Relational Model?", options: ["Data is represented as relations", "Relationships are represented by data values", "Physical storage details are visible to users", "Each relation has a unique name"], answer: 2, explanation: "In the relational model, physical storage details are hidden from the user (Data Independence)." },
  { topic: "database", question: "What does 'Physical Data Independence' mean?", options: ["Users can change their view without affecting others", "Internal schema can be changed without affecting the conceptual schema", "External schema can be changed without affecting the internal schema", "The hardware can be changed without rebooting"], answer: 1, explanation: "It refers to the ability to modify the physical storage/internal schema without changing the logical/conceptual schema." },
  { topic: "database", question: "The 'Database State' or 'Snapshot' refers to:", options: ["The design of the database", "The data in the database at a specific moment in time", "The set of all possible queries", "The physical storage size"], answer: 1, explanation: "The state (or instance) of the database changes every time an update is performed." },
  { topic: "database", question: "Which model uses 'Nodes' and 'Edges' to represent data and relationships?", options: ["Relational Model", "Network Model", "Flat File Model", "Semi-structured Model"], answer: 1, explanation: "The network model represents data as records and relationships as links (pointers)." },
  { topic: "database", question: "Which of the following is a disadvantage of a DBMS?", options: ["Reduced data redundancy", "High complexity and cost", "Improved data integrity", "Ease of data sharing"], answer: 1, explanation: "DBMS systems can be expensive to acquire, maintain, and require skilled personnel." },
  { topic: "database", question: "In a 'Client-Server' DBMS architecture, the 'Back-end' usually refers to:", options: ["The user interface", "The client application", "The database server", "The web browser"], answer: 2, explanation: "The server handles data storage, retrieval, and management (back-end)." },
  { topic: "database", question: "What is the 'Database Catalog'?", options: ["A list of all users", "A directory of all physical files", "A repository containing metadata like table and column definitions", "A collection of all SQL queries"], answer: 2, explanation: "The catalog (or data dictionary) stores information about the database structure." },
  { topic: "database", question: "Which of the following is an example of 'Unstructured Data'?", options: ["A SQL table", "An Excel spreadsheet", "A collection of video files", "A JSON document"], answer: 2, explanation: "Unstructured data lacks a predefined data model (e.g., images, videos, audio)." },
  { topic: "database", question: "What is 'Data Redundancy'?", options: ["Storing data in multiple locations unnecessarily", "Losing data due to system failure", "Encrypting data for security", "Deleting data that is no longer needed"], answer: 0, explanation: "Redundancy is the duplication of data, which can lead to inconsistency." },
  { topic: "database", question: "The 'Schema-on-read' approach is typical for:", options: ["Relational Databases", "NoSQL / Big Data systems", "Mainframe databases", "Static spreadsheets"], answer: 1, explanation: "NoSQL systems often apply structure only when the data is read, rather than when it is stored." },
  { topic: "database", question: "What is the role of the 'Query Processor' in a DBMS?", options: ["To store data on disk", "To interpret and optimize SQL queries into execution plans", "To manage user passwords", "To format the output on the screen"], answer: 1, explanation: "The query processor parses and optimizes SQL commands." },
  { topic: "database", question: "Which of the following is NOT a data model?", options: ["Entity-Relationship Model", "Relational Model", "Structured Query Language", "Object-Relational Model"], answer: 2, explanation: "SQL is a language used to interact with a database, not a data model itself." },
  { topic: "database", question: "In the three-tier architecture, the intermediate layer between client and database is:", options: ["Presentation Layer", "Application Layer", "Data Layer", "Network Layer"], answer: 1, explanation: "The application layer contains the business logic." },
  { topic: "database", question: "What is 'Data Inconsistency'?", options: ["When data is deleted accidentally", "When different versions of the same data exist in the database", "When data is encrypted with different keys", "When the database is offline"], answer: 1, explanation: "Inconsistency occurs when redundant data is not updated simultaneously in all locations." },
  { topic: "database", question: "The property that ensures only authorized users can perform specific operations is:", options: ["Concurrency Control", "Integrity Control", "Security Control", "Recovery Control"], answer: 2, explanation: "Security control (or Authorization) manages permissions." },
  { topic: "database", question: "Which type of DBMS user writes complex application programs to interact with the database?", options: ["Naive User", "Sophisticated User", "Application Programmer", "Specialized User"], answer: 2, explanation: "Application programmers use DML calls to develop software." },
  { topic: "database", question: "A 'Distributed Database' is one where:", options: ["All data is stored on one central server", "Data is spread across multiple physical locations", "Multiple users access the same file", "The database is shared via email"], answer: 1, explanation: "In a distributed DB, data is stored on different computers across a network." },
  { topic: "database", question: "Which of the following is a 'Conceptual' data model?", options: ["Relational Model", "ER Model", "Internal Model", "Physical Model"], answer: 1, explanation: "The ER model is a high-level conceptual model used for database design." },
  { topic: "database", question: "The 'Database Environment' includes:", options: ["Only the data", "The DBMS software, data, and users", "Only the SQL language", "Only the hardware"], answer: 1, explanation: "The environment includes software, hardware, data, procedures, and users." },
  { topic: "database", question: "What is 'Self-describing' nature of a DBMS?", options: ["The database can repair itself", "The database includes a description of its own structure in the catalog", "Users can understand the data without help", "The data is stored in plain text"], answer: 1, explanation: "A DBMS is self-describing because it stores metadata in the data dictionary." },
  { topic: "database", question: "Which operation is used to combine data from two or more tables?", options: ["Selection", "Projection", "Join", "Aggregation"], answer: 2, explanation: "Joins are used to link records from different tables based on common fields." },
  { topic: "database", question: "The 'End Users' who use the database to generate reports but don't write code are:", options: ["Sophisticated Users", "Casual End Users", "Parametric End Users", "DBA"], answer: 1, explanation: "Casual users access the DB occasionally with different needs each time." },
  { topic: "database", question: "What is the 'Integrity Constraint' in a DBMS?", options: ["A rule that restricts the values allowed in the database", "A method for encrypting data", "A way to speed up queries", "A backup procedure"], answer: 0, explanation: "Integrity constraints (like PK, FK, NOT NULL) ensure data correctness." },
  { topic: "database", question: "Which of the following is NOT an advantage of the DBMS approach?", options: ["Restricting unauthorized access", "Providing persistent storage for program objects", "Allowing data to be stored twice to ensure safety", "Enforcing integrity constraints"], answer: 2, explanation: "DBMS aims to *reduce* redundancy, not encourage it for 'safety' (backups are different)." },
  { topic: "database", question: "The 'Transaction Manager' ensures:", options: ["The UI looks good", "ACID properties are maintained", "The internet connection is stable", "Queries are sorted alphabetically"], answer: 1, explanation: "It handles transactions to ensure Atomicity, Consistency, Isolation, and Durability." },
  { topic: "database", question: "A DBMS that supports multiple users simultaneously is called:", options: ["Single-user system", "Multi-user system", "Distributed system", "Real-time system"], answer: 1, explanation: "Multi-user systems use concurrency control to allow shared access." },
  { topic: "database", question: "Which language is used by the DBA to define the internal schema?", options: ["VDL (View Definition Language)", "SDL (Storage Definition Language)", "DML", "DCL"], answer: 1, explanation: "SDL is used to specify the internal/physical storage structure." },
  { topic: "database", question: "The 'Mapping' between levels in the 3-level architecture is used to provide:", options: ["Security", "Data Independence", "Faster access", "Larger storage"], answer: 1, explanation: "Mappings translate requests between external, conceptual, and internal levels." },
  { topic: "database", question: "What is 'Semi-structured' data?", options: ["Data with no structure at all", "Data that has some organizational properties but doesn't fit a relational schema (e.g. XML, JSON)", "Data that is half-encrypted", "Data stored in Excel"], answer: 1, explanation: "XML and JSON are semi-structured because they use tags/keys but aren't strictly tabular." },

  // 2. Relational Model (40 Qs)
  { topic: "database", question: "In the relational model, a 'Relation' is synonymous with a:", options: ["Column", "Row", "Table", "Constraint"], answer: 2, explanation: "A relation is a mathematical term for a table." },
  { topic: "database", question: "A 'Tuple' in a relation represents a:", options: ["Attribute", "Table", "Row / Record", "Domain"], answer: 2, explanation: "Each row in a table is called a tuple." },
  { topic: "database", question: "The number of attributes in a relation is called its:", options: ["Cardinality", "Degree", "Dimension", "Order"], answer: 1, explanation: "Degree refers to the number of columns (attributes) in a table." },
  { topic: "database", question: "The number of tuples in a relation is called its:", options: ["Degree", "Cardinality", "Scale", "Density"], answer: 1, explanation: "Cardinality refers to the number of rows (tuples) in a table." },
  { topic: "database", question: "Which of the following is a minimal set of attributes that uniquely identifies a tuple?", options: ["Super Key", "Candidate Key", "Foreign Key", "Secondary Key"], answer: 1, explanation: "A candidate key is a minimal super key." },
  { topic: "database", question: "A 'Primary Key' is:", options: ["Any super key", "A candidate key chosen to uniquely identify tuples", "A key that can be NULL", "A key used for encryption"], answer: 1, explanation: "The PK is the specific candidate key selected by the designer." },
  { topic: "database", question: "A 'Foreign Key' is used to:", options: ["Uniquely identify a row in the same table", "Establish a relationship between two tables", "Speed up search operations", "Store data from a foreign country"], answer: 1, explanation: "A FK in one table refers to the PK of another table." },
  { topic: "database", question: "What is 'Referential Integrity'?", options: ["Every primary key must be unique", "Every foreign key value must match a primary key value in the referenced table (or be NULL)", "No attribute can be NULL", "Data must be stored in alphabetical order"], answer: 1, explanation: "It ensures that relationships between tables remain consistent." },
  { topic: "database", question: "An attribute that is a part of the primary key is called a:", options: ["Prime Attribute", "Non-prime Attribute", "Foreign Attribute", "Derived Attribute"], answer: 0, explanation: "Attributes belonging to any candidate key are prime attributes." },
  { topic: "database", question: "What is a 'Super Key'?", options: ["A key with the most attributes", "Any set of attributes that uniquely identifies a tuple", "The first column in a table", "A key that cannot be changed"], answer: 1, explanation: "A super key is any set of attributes that ensures uniqueness." },
  { topic: "database", question: "A 'Composite Key' is a key that:", options: ["Consists of more than one attribute", "Is used in multiple tables", "Is generated automatically by the DBMS", "Contains special characters"], answer: 0, explanation: "Composite keys use two or more columns to identify a record uniquely." },
  { topic: "database", question: "In relational algebra, which operator is used to select a subset of rows?", options: ["Projection (π)", "Selection (σ)", "Join (⨝)", "Union (∪)"], answer: 1, explanation: "Selection (sigma) filters rows based on a condition." },
  { topic: "database", question: "In relational algebra, which operator is used to select a subset of columns?", options: ["Selection (σ)", "Projection (π)", "Division (÷)", "Intersection (∩)"], answer: 1, explanation: "Projection (pi) filters columns." },
  { topic: "database", question: "The 'Domain' of an attribute is:", options: ["The name of the table", "The set of all possible atomic values for that attribute", "The primary key of the table", "The physical location on disk"], answer: 1, explanation: "A domain defines the data type and valid range of values." },
  { topic: "database", question: "Which of the following is a 'Set' operation in relational algebra?", options: ["Selection", "Projection", "Union", "Join"], answer: 2, explanation: "Union, Intersection, and Set Difference are standard set operations." },
  { topic: "database", question: "A 'Cartesian Product' (R x S) results in a relation with:", options: ["The sum of tuples of R and S", "The product of tuples of R and S", "Only the matching tuples", "The difference of tuples"], answer: 1, explanation: "If R has n tuples and S has m, R x S has n * m tuples." },
  { topic: "database", question: "What is the degree of a relation resulting from the Cartesian Product of R(A, B) and S(C, D, E)?", options: ["2", "3", "5", "6"], answer: 2, explanation: "The degree of R x S is the sum of the degrees of R and S (2 + 3 = 5)." },
  { topic: "database", question: "Which relational algebra operator is equivalent to a 'Selection' followed by a 'Cartesian Product'?", options: ["Natural Join", "Theta Join", "Outer Join", "Union"], answer: 1, explanation: "Theta join is a Cartesian product followed by a selection condition." },
  { topic: "database", question: "A 'Natural Join' (⨝) is based on:", options: ["A user-defined condition", "Equality of all common attributes", "The first column of each table", "Random matching"], answer: 1, explanation: "Natural join matches rows where all attributes with the same name have equal values." },
  { topic: "database", question: "What is the 'Entity Integrity' constraint?", options: ["Foreign keys cannot be NULL", "Primary key cannot be NULL", "Every table must have a foreign key", "Data must be encrypted"], answer: 1, explanation: "Entity integrity states that no part of a primary key can be null." },
  { topic: "database", question: "Which of the following is a non-procedural language?", options: ["Relational Algebra", "Relational Calculus", "C++", "Java"], answer: 1, explanation: "Relational calculus is declarative (describes *what* is wanted, not *how* to get it)." },
  { topic: "database", question: "Tuple Relational Calculus (TRC) uses variables that range over:", options: ["Attributes", "Domains", "Tuples", "Tables"], answer: 2, explanation: "In TRC, variables represent rows (tuples) of a relation." },
  { topic: "database", question: "Domain Relational Calculus (DRC) uses variables that range over:", options: ["Tuples", "Tables", "Attribute values (domains)", "Primary keys"], answer: 2, explanation: "In DRC, variables represent values from the domains of attributes." },
  { topic: "database", question: "The 'Division' operator (R ÷ S) is used when a query contains the word:", options: ["OR", "AND", "SOME", "ALL"], answer: 3, explanation: "Division is used for 'Find X that are associated with *all* Y in S'." },
  { topic: "database", question: "Which of the following operations is NOT commutative?", options: ["Union", "Intersection", "Set Difference", "Natural Join"], answer: 2, explanation: "R - S is not the same as S - R." },
  { topic: "database", question: "In a relation, the order of rows is:", options: ["Significant", "Insignificant", "Alphabetical", "Numeric"], answer: 1, explanation: "A relation is a set of tuples; the order does not matter." },
  { topic: "database", question: "The 'Rename' operator (ρ) is used to:", options: ["Change the name of a table or attribute", "Delete a table", "Create a copy of a database", "Update a row value"], answer: 0, explanation: "Rho (ρ) is used to rename relations or attributes in expressions." },
  { topic: "database", question: "Which of the following is NOT a fundamental operator in relational algebra?", options: ["Selection", "Projection", "Union", "Intersection"], answer: 3, explanation: "Intersection can be derived from Set Difference (R ∩ S = R - (R - S))." },
  { topic: "database", question: "A relation is in 'First Normal Form' (1NF) if:", options: ["It has no foreign keys", "All attribute values are atomic", "It has a composite key", "It is linked to another table"], answer: 1, explanation: "1NF prohibits multivalued attributes and nested relations." },
  { topic: "database", question: "The 'NULL' value represents:", options: ["Zero", "Empty string", "Unknown or not applicable value", "A space"], answer: 2, explanation: "NULL is a special marker indicating that a data value does not exist." },
  { topic: "database", question: "What is 'Relational Completeness'?", options: ["The database is full", "A language is as powerful as relational algebra", "All tables have primary keys", "The database is in 3NF"], answer: 1, explanation: "A query language is relationally complete if it can express any query expressible in relational algebra." },
  { topic: "database", question: "The 'Self-Join' is a join where:", options: ["A table is joined with itself", "A table is joined with its backup", "Two tables with the same name are joined", "Only the primary key is used"], answer: 0, explanation: "Self-join is useful for hierarchical data within one table (e.g., Employees and Managers)." },
  { topic: "database", question: "Which join returns all rows from both tables, matching them where possible?", options: ["Left Outer Join", "Right Outer Join", "Full Outer Join", "Inner Join"], answer: 2, explanation: "Full Outer Join combines results of both Left and Right joins." },
  { topic: "database", question: "What is the 'Degree' of the result of a Union operation between R(A, B) and S(A, B)?", options: ["2", "4", "0", "Undefined"], answer: 0, explanation: "Union requires tables to be union-compatible (same degree and domains); the result has the same degree (2)." },
  { topic: "database", question: "Which of the following is a constraint on the entire relation rather than a single tuple?", options: ["Key constraint", "Check constraint", "Not Null constraint", "Default value"], answer: 0, explanation: "A key constraint (uniqueness) must be checked against all tuples in the relation." },
  { topic: "database", question: "The 'Base Relation' is:", options: ["A temporary table", "A table that physically exists in the database", "A view", "A subquery"], answer: 1, explanation: "Base relations are the actual tables stored on disk." },
  { topic: "database", question: "In relational algebra, the 'Intersection' operator is:", options: ["Binary", "Unary", "Ternary", "Logical"], answer: 0, explanation: "Intersection (∩) operates on two relations." },
  { topic: "database", question: "A 'Weak Entity' is one that:", options: ["Has no primary key", "Cannot exist without a related strong entity", "Has only one attribute", "Is not stored on disk"], answer: 1, explanation: "Weak entities depend on an identifying owner entity." },
  { topic: "database", question: "The 'Relational Data Model' was proposed by:", options: ["Bill Gates", "E.F. Codd", "Larry Ellison", "James Gosling"], answer: 1, explanation: "Dr. Edgar F. Codd introduced the relational model in 1970." },
  { topic: "database", question: "Which operation reduces the 'Cardinality' of a relation?", options: ["Selection", "Projection", "Join", "Union"], answer: 0, explanation: "Selection filters out rows, thus reducing the number of tuples (cardinality)." },

  // 3. SQL Queries (50 Qs)
  { topic: "database", question: "Which SQL clause is used to filter rows before grouping?", options: ["WHERE", "HAVING", "ORDER BY", "GROUP BY"], answer: 0, explanation: "WHERE filters rows before aggregation; HAVING filters groups after aggregation." },
  { topic: "database", question: "Which SQL keyword is used to return only unique values?", options: ["UNIQUE", "DISTINCT", "DIFFERENT", "SINGLE"], answer: 1, explanation: "SELECT DISTINCT removes duplicate rows from the output." },
  { topic: "database", question: "What is the correct order of clauses in a SELECT statement?", options: ["SELECT, FROM, WHERE, GROUP BY, HAVING, ORDER BY", "SELECT, FROM, GROUP BY, WHERE, HAVING, ORDER BY", "SELECT, WHERE, FROM, GROUP BY, HAVING, ORDER BY", "SELECT, FROM, ORDER BY, WHERE, GROUP BY, HAVING"], answer: 0, explanation: "The standard order is SELECT -> FROM -> WHERE -> GROUP BY -> HAVING -> ORDER BY." },
  { topic: "database", question: "Which operator is used for pattern matching in SQL?", options: ["MATCH", "LIKE", "SEARCH", "CONTAINS"], answer: 1, explanation: "The LIKE operator is used with wildcards (% and _)." },
  { topic: "database", question: "In SQL, the '_' wildcard matches:", options: ["Zero or more characters", "Exactly one character", "Any number of characters", "Only digits"], answer: 1, explanation: "The underscore (_) represents a single character." },
  { topic: "database", question: "In SQL, the '%' wildcard matches:", options: ["Exactly one character", "Zero, one, or multiple characters", "Only percentage signs", "Special characters"], answer: 1, explanation: "The percent (%) sign represents zero or more characters." },
  { topic: "database", question: "Which command is used to remove all records from a table without deleting the table structure?", options: ["DELETE", "DROP", "TRUNCATE", "REMOVE"], answer: 2, explanation: "TRUNCATE is a DDL command that removes all rows quickly and cannot be rolled back easily in some systems." },
  { topic: "database", question: "Which clause is used with aggregate functions to filter the results?", options: ["WHERE", "HAVING", "FILTER", "LIMIT"], answer: 1, explanation: "HAVING is used to filter groups based on aggregate values (e.g., HAVING COUNT(*) > 5)." },
  { topic: "database", question: "What is the result of 'SELECT 5 + NULL' in SQL?", options: ["5", "0", "NULL", "Error"], answer: 2, explanation: "Any arithmetic operation with NULL results in NULL." },
  { topic: "database", question: "Which join returns all rows from the left table even if there are no matches in the right table?", options: ["INNER JOIN", "LEFT JOIN", "RIGHT JOIN", "FULL JOIN"], answer: 1, explanation: "LEFT JOIN (or LEFT OUTER JOIN) ensures all left table rows are included." },
  { topic: "database", question: "A 'Correlated Subquery' is one that:", options: ["Runs independently of the outer query", "Depends on values from the outer query for its execution", "Returns a table", "Is used in the FROM clause"], answer: 1, explanation: "Correlated subqueries are executed once for each row processed by the outer query." },
  { topic: "database", question: "Which SQL command is used to change data in an existing table?", options: ["CHANGE", "MODIFY", "UPDATE", "ALTER"], answer: 2, explanation: "UPDATE is used to modify values in rows; ALTER is used to modify the table structure." },
  { topic: "database", question: "The 'IN' operator is used to:", options: ["Check if a value matches any value in a list or subquery", "Join two tables", "Sort the output", "Check for NULL values"], answer: 0, explanation: "IN is a shorthand for multiple OR conditions." },
  { topic: "database", question: "The 'BETWEEN' operator in SQL is:", options: ["Exclusive", "Inclusive", "Random", "Used only for dates"], answer: 1, explanation: "BETWEEN includes both the start and end values." },
  { topic: "database", question: "Which command is used to add a new column to an existing table?", options: ["UPDATE TABLE", "ALTER TABLE ADD", "INSERT INTO", "MODIFY TABLE"], answer: 1, explanation: "ALTER TABLE is used to change the schema of a table." },
  { topic: "database", question: "To sort results in descending order, which keyword is used?", options: ["ASC", "DESC", "DOWN", "REVERSE"], answer: 1, explanation: "DESC stands for descending; ASC is the default for ascending." },
  { topic: "database", question: "Which SQL operator is used to combine the results of two SELECT statements and remove duplicates?", options: ["UNION", "UNION ALL", "INTERSECT", "EXCEPT"], answer: 0, explanation: "UNION combines results and removes duplicates; UNION ALL keeps duplicates." },
  { topic: "database", question: "What does the 'EXISTS' operator do?", options: ["Checks if a column exists", "Returns true if the subquery returns at least one row", "Deletes a row if it exists", "Checks for NULL values"], answer: 1, explanation: "EXISTS is used to test for the existence of any record in a subquery." },
  { topic: "database", question: "Which SQL keyword is used to specify a temporary name for a table or column?", options: ["RENAME", "AS", "SET", "NAME"], answer: 1, explanation: "AS is used to create an alias." },
  { topic: "database", question: "A 'Cross Join' results in:", options: ["Only matching rows", "A Cartesian Product of both tables", "All rows from the first table", "An error"], answer: 1, explanation: "CROSS JOIN produces a Cartesian product (every row of A paired with every row of B)." },
  { topic: "database", question: "Which command is used to delete a table and its data permanently?", options: ["DELETE", "TRUNCATE", "DROP", "REMOVE"], answer: 2, explanation: "DROP TABLE removes the data and the definition from the database." },
  { topic: "database", question: "The 'ALL' keyword in a subquery (e.g., > ALL) means:", options: ["At least one value must match", "The condition must be true for every value in the subquery result", "All columns are selected", "The query returns all rows"], answer: 1, explanation: "v > ALL (1, 2, 3) means v must be greater than 3." },
  { topic: "database", question: "The 'ANY' keyword in a subquery (e.g., > ANY) means:", options: ["The condition must be true for at least one value in the subquery result", "All values must match", "The query is invalid", "Only the first value is checked"], answer: 0, explanation: "v > ANY (1, 2, 3) means v must be greater than at least one of them (i.e., v > 1)." },
  { topic: "database", question: "Which SQL function is used to find the number of rows in a table?", options: ["SUM()", "TOTAL()", "COUNT()", "NUMBER()"], answer: 2, explanation: "COUNT(*) or COUNT(column) returns the number of rows." },
  { topic: "database", question: "Which clause is used to limit the number of rows returned in a result set (standard SQL)?", options: ["LIMIT", "TOP", "FETCH FIRST", "ROWS"], answer: 2, explanation: "While LIMIT is common in MySQL/PostgreSQL, 'FETCH FIRST n ROWS ONLY' is the SQL standard (SQL:2008)." },
  { topic: "database", question: "Which statement is used to insert multiple rows into a table in one command?", options: ["INSERT ALL", "INSERT INTO table VALUES (...), (...)", "INSERT MULTIPLE", "UPDATE INSERT"], answer: 1, explanation: "Standard SQL allows multiple value tuples in the VALUES clause." },
  { topic: "database", question: "How do you select all columns from a table named 'Employees'?", options: ["SELECT Employees", "SELECT * FROM Employees", "SELECT ALL FROM Employees", "DISPLAY Employees"], answer: 1, explanation: "The asterisk (*) is a shorthand for 'all columns'." },
  { topic: "database", question: "Which SQL operator is used to test for empty values?", options: ["= NULL", "IS NULL", "EMPTY", "IS NOT EMPTY"], answer: 1, explanation: "Since NULL is not a value, you must use 'IS NULL' or 'IS NOT NULL' instead of '='." },
  { topic: "database", question: "What is the purpose of the 'GROUP BY' clause?", options: ["To sort the output", "To arrange identical data into groups", "To filter rows", "To join tables"], answer: 1, explanation: "GROUP BY is used with aggregate functions to group the result-set by one or more columns." },
  { topic: "database", question: "Which join is used to find records that have matching values in both tables?", options: ["OUTER JOIN", "INNER JOIN", "CROSS JOIN", "LEFT JOIN"], answer: 1, explanation: "INNER JOIN selects records that have matching values in both tables." },
  { topic: "database", question: "A 'Natural Join' is problematic because:", options: ["It is too slow", "It might join tables on columns with same names but different meanings", "It requires a WHERE clause", "It doesn't support NULLs"], answer: 1, explanation: "It relies on column names, which can lead to accidental joins." },
  { topic: "database", question: "Which command is used to give permissions to a user?", options: ["ALLOW", "PERMIT", "GRANT", "AUTHORIZE"], answer: 2, explanation: "GRANT is a DCL (Data Control Language) command." },
  { topic: "database", question: "Which command is used to take away permissions from a user?", options: ["DENY", "REVOKE", "REMOVE", "WITHDRAW"], answer: 1, explanation: "REVOKE is the DCL command used to remove privileges." },
  { topic: "database", question: "A subquery in the FROM clause is called a:", options: ["Scalar subquery", "Inline View / Derived Table", "Correlated subquery", "Nested query"], answer: 1, explanation: "Subqueries in the FROM clause act as temporary tables." },
  { topic: "database", question: "Which of the following is NOT a valid SQL aggregate function?", options: ["SUM", "AVG", "MAX", "LIST"], answer: 3, explanation: "SUM, AVG, MIN, MAX, and COUNT are standard; LIST is not." },
  { topic: "database", question: "How can you change 'Hanson' to 'Nilsen' in the 'LastName' column of the 'Persons' table?", options: ["UPDATE Persons SET LastName='Hanson' INTO LastName='Nilsen'", "UPDATE Persons SET LastName='Nilsen' WHERE LastName='Hanson'", "MODIFY Persons SET LastName='Nilsen' WHERE LastName='Hanson'", "SET Persons LastName='Nilsen' WHERE LastName='Hanson'"], answer: 1, explanation: "UPDATE [table] SET [col]=[val] WHERE [cond] is the correct syntax." },
  { topic: "database", question: "How can you delete the persons whose 'FirstName' is 'Peter'?", options: ["DELETE FROM Persons WHERE FirstName = 'Peter'", "DELETE FirstName='Peter' FROM Persons", "DROP FROM Persons WHERE FirstName = 'Peter'", "REMOVE Peter FROM Persons"], answer: 0, explanation: "DELETE is used to remove rows; the WHERE clause specifies which rows." },
  { topic: "database", question: "What is the 'Self-Join' syntax typically?", options: ["SELECT ... FROM Table1 T1, Table1 T2 WHERE T1.id = T2.parent_id", "SELECT ... FROM Table1 JOIN Table1", "SELECT ... FROM Table1 SELF JOIN", "SELECT ... FROM Table1 + Table1"], answer: 0, explanation: "Self-join requires using aliases for the same table to distinguish them." },
  { topic: "database", question: "Which SQL keyword is used to define a constraint while creating a table?", options: ["RULE", "CHECK", "VALIDATE", "LIMIT"], answer: 1, explanation: "The CHECK constraint is used to limit the value range that can be placed in a column." },
  { topic: "database", question: "What is 'SQL Injection'?", options: ["A way to speed up SQL queries", "A security vulnerability where an attacker can execute arbitrary SQL code", "A method to import data into a database", "A specific type of SQL join"], answer: 1, explanation: "It occurs when malicious SQL statements are inserted into an entry field for execution." },
  { topic: "database", question: "Which operator is used to combine results but keep ONLY the common rows?", options: ["UNION", "INTERSECT", "EXCEPT", "MINUS"], answer: 1, explanation: "INTERSECT returns the intersection of two result sets." },
  { topic: "database", question: "Which operator is used to return rows from the first query that are not in the second?", options: ["EXCEPT / MINUS", "NOT IN", "DIFFERENCE", "REMOVE"], answer: 0, explanation: "EXCEPT (SQL standard) or MINUS (Oracle) returns the set difference." },
  { topic: "database", question: "In a SELECT statement, what does 'ORDER BY 1' mean?", options: ["Sort by the first record", "Sort by the first column in the SELECT list", "Sort by the primary key", "Syntax error"], answer: 1, explanation: "Numeric positions in ORDER BY refer to the column index in the SELECT clause." },
  { topic: "database", question: "Which SQL command is used to save changes made in a transaction?", options: ["SAVE", "COMMIT", "ROLLBACK", "FINISH"], answer: 1, explanation: "COMMIT makes all changes made during the current transaction permanent." },
  { topic: "database", question: "Which command is used to undo changes made in a transaction?", options: ["UNDO", "ROLLBACK", "BACKUP", "REVERT"], answer: 1, explanation: "ROLLBACK reverts the database to the state it was in before the transaction started." },
  { topic: "database", question: "A 'Scalar Subquery' is a subquery that returns:", options: ["Multiple rows", "Multiple columns", "Exactly one value (one row, one column)", "A boolean"], answer: 2, explanation: "Scalar subqueries can be used anywhere an expression is allowed." },
  { topic: "database", question: "What is the default join type in SQL if you just write 'JOIN'?", options: ["LEFT JOIN", "RIGHT JOIN", "INNER JOIN", "CROSS JOIN"], answer: 2, explanation: "JOIN by itself defaults to INNER JOIN." },
  { topic: "database", question: "Which clause is used to sort the result-set?", options: ["SORT BY", "ORDER BY", "ARRANGE BY", "GROUP BY"], answer: 1, explanation: "ORDER BY is used to sort the results." },
  { topic: "database", question: "Which of the following is a DCL command?", options: ["CREATE", "SELECT", "GRANT", "UPDATE"], answer: 2, explanation: "Data Control Language (DCL) includes GRANT and REVOKE." },
  { topic: "database", question: "The 'LIKE' pattern '%a_' matches:", options: ["Any string ending with 'a'", "Any string having 'a' as the second to last character", "Any string starting with 'a'", "Any string containing 'a'"], answer: 1, explanation: "'%' matches any prefix, 'a' is the character, and '_' matches exactly one character after it." },

  // 4. SQL Functions (30 Qs)
  { topic: "database", question: "Which function returns the average value of a numeric column?", options: ["AVERAGE()", "AVG()", "MEAN()", "SUM()/COUNT()"], answer: 1, explanation: "AVG() is the standard SQL function for average." },
  { topic: "database", question: "What does the COALESCE function do?", options: ["Combines two strings", "Returns the first non-null value in a list", "Counts the number of null values", "Encrypts a string"], answer: 1, explanation: "COALESCE(val1, val2, ...) evaluates arguments in order and returns the first non-null." },
  { topic: "database", question: "Which function is used to convert a string to uppercase?", options: ["UPPER()", "UCASE()", "CAPS()", "Both A and B (depending on DBMS)"], answer: 3, explanation: "UPPER() is standard, while UCASE() is used in MySQL and others." },
  { topic: "database", question: "Which function is used to return the length of a string?", options: ["LEN()", "LENGTH()", "SIZE()", "Both LEN() and LENGTH()"], answer: 3, explanation: "LENGTH() is standard; LEN() is used in SQL Server." },
  { topic: "database", question: "The 'CAST' function is used to:", options: ["Rename a column", "Change the data type of an expression", "Sort data", "Format a date"], answer: 1, explanation: "CAST(expression AS data_type) converts values between types." },
  { topic: "database", question: "Which function is used to extract a portion of a string?", options: ["PART()", "SUBSTRING()", "EXTRACT()", "SLICE()"], answer: 1, explanation: "SUBSTRING(string, start, length) is the standard function." },
  { topic: "database", question: "The 'ROUND()' function is used to:", options: ["Round a number to a specified number of decimal places", "Find the next integer", "Format a string as a circle", "Calculate the area of a circle"], answer: 0, explanation: "ROUND(column_name, decimals) rounds a numeric field." },
  { topic: "database", question: "Which function returns the current date and time?", options: ["GETDATE()", "NOW()", "CURRENT_TIMESTAMP", "All of the above (depending on DBMS)"], answer: 3, explanation: "Different systems use different names; CURRENT_TIMESTAMP is the SQL standard." },
  { topic: "database", question: "The 'CONCAT()' function is used to:", options: ["Split a string", "Join two or more strings", "Compare strings", "Count characters"], answer: 1, explanation: "CONCAT() appends strings together." },
  { topic: "database", question: "Which function is used to remove leading and trailing spaces from a string?", options: ["REMOVE()", "CLEAN()", "TRIM()", "STRIP()"], answer: 2, explanation: "TRIM() removes whitespace from both ends." },
  { topic: "database", question: "The 'CEILING()' function returns:", options: ["The smallest integer greater than or equal to a number", "The largest integer less than or equal to a number", "The absolute value", "A random number"], answer: 0, explanation: "CEILING(25.75) returns 26." },
  { topic: "database", question: "The 'FLOOR()' function returns:", options: ["The smallest integer greater than or equal to a number", "The largest integer less than or equal to a number", "The square root", "The remainder"], answer: 1, explanation: "FLOOR(25.75) returns 25." },
  { topic: "database", question: "Which function returns the remainder of a division?", options: ["REM()", "MOD()", "DIV()", "% (operator)"], answer: 1, explanation: "MOD(n, m) or the % operator returns the modulus." },
  { topic: "database", question: "The 'ABS()' function returns:", options: ["The average", "The absolute value of a number", "The ASCII code", "The abbreviated name"], answer: 1, explanation: "ABS(-5) returns 5." },
  { topic: "database", question: "In SQL, what is the 'CASE' statement used for?", options: ["To handle errors", "To implement if-then-else logic in a query", "To create a new table", "To sort data"], answer: 1, explanation: "CASE allows conditional logic within SQL statements." },
  { topic: "database", question: "Which function can be used to replace NULL with a default value in SQL Server?", options: ["IFNULL()", "NVL()", "ISNULL()", "COALESCE()"], answer: 2, explanation: "SQL Server uses ISNULL(); MySQL uses IFNULL(); Oracle uses NVL(). COALESCE is standard." },
  { topic: "database", question: "Which function returns the largest value in a column?", options: ["LARGEST()", "TOP()", "MAX()", "HIGH()"], answer: 2, explanation: "MAX() returns the maximum value." },
  { topic: "database", question: "Which function returns the smallest value in a column?", options: ["SMALLEST()", "BOTTOM()", "MIN()", "LOW()"], answer: 2, explanation: "MIN() returns the minimum value." },
  { topic: "database", question: "The 'DATEDIFF()' function is used to:", options: ["Add days to a date", "Return the difference between two dates", "Format a date", "Check if a date is valid"], answer: 1, explanation: "It calculates the time between two date values." },
  { topic: "database", question: "Which function is used to convert a number to a string?", options: ["STR()", "TO_CHAR()", "CONVERT()", "All of the above"], answer: 3, explanation: "Different dialects have different functions for type conversion." },
  { topic: "database", question: "What does 'NULLIF(val1, val2)' return if val1 equals val2?", options: ["0", "NULL", "1", "val1"], answer: 1, explanation: "NULLIF returns NULL if the two expressions are equal; otherwise, it returns the first expression." },
  { topic: "database", question: "Which function is used to find the starting position of a substring within a string?", options: ["SEARCH()", "FIND()", "INSTR() / POSITION()", "LOCATE()"], answer: 2, explanation: "INSTR (Oracle/MySQL) or POSITION (Standard) find substring locations." },
  { topic: "database", question: "The 'REPLACE()' function is used to:", options: ["Change a column name", "Replace all occurrences of a substring within a string with another substring", "Update a row in a table", "Swap two columns"], answer: 1, explanation: "REPLACE(string, search, replacement) modifies the string content." },
  { topic: "database", question: "Which aggregate function ignores NULL values?", options: ["COUNT(*)", "COUNT(column)", "SUM(column)", "Both B and C"], answer: 3, explanation: "Aggregate functions like SUM, AVG, and COUNT(col) ignore NULLs. COUNT(*) counts all rows." },
  { topic: "database", question: "What is the result of 'SELECT LENGTH('  SQL  ')'?", options: ["3", "5", "7", "Depends on the system"], answer: 2, explanation: "LENGTH includes leading and trailing spaces unless TRIM is used." },
  { topic: "database", question: "The 'POWER(x, y)' function returns:", options: ["x multiplied by y", "x raised to the power of y", "Square root of x", "Natural log of x"], answer: 1, explanation: "POWER(2, 3) returns 8." },
  { topic: "database", question: "Which function returns a random number between 0 and 1?", options: ["RAND()", "RANDOM()", "Both A and B", "NONE"], answer: 2, explanation: "RAND() is used in MySQL/SQL Server; RANDOM() in PostgreSQL/SQLite." },
  { topic: "database", question: "The 'SQRT()' function returns:", options: ["Square", "Square root", "Sequence", "None"], answer: 1, explanation: "SQRT(16) returns 4." },
  { topic: "database", question: "Which function extracts the year from a date?", options: ["YEAR()", "EXTRACT(YEAR FROM date)", "Both A and B", "GET_YEAR()"], answer: 2, explanation: "Many systems support YEAR(), and SQL standard supports EXTRACT." },
  { topic: "database", question: "Aggregate functions can be used in:", options: ["WHERE clause", "SELECT list and HAVING clause", "FROM clause", "ORDER BY clause"], answer: 1, explanation: "Aggregates are processed after WHERE; they appear in the output or group filters." },

  // 5. Normalization (40 Qs)
  { topic: "database", question: "The main goal of normalization is to:", options: ["Increase redundancy", "Eliminate anomalies and reduce redundancy", "Speed up data entry", "Make the database harder to query"], answer: 1, explanation: "Normalization organizes data to minimize duplication and prevent update/delete/insert anomalies." },
  { topic: "database", question: "A relation is in 'Second Normal Form' (2NF) if it is in 1NF and:", options: ["It has no partial dependencies", "It has no transitive dependencies", "It has no multivalued attributes", "It has a foreign key"], answer: 0, explanation: "2NF requires that all non-prime attributes are fully functionally dependent on the primary key." },
  { topic: "database", question: "A 'Partial Dependency' occurs when:", options: ["A non-prime attribute depends on only part of a composite primary key", "A non-prime attribute depends on another non-prime attribute", "The primary key is NULL", "Two attributes depend on each other"], answer: 0, explanation: "This violates 2NF." },
  { topic: "database", question: "A relation is in 'Third Normal Form' (3NF) if it is in 2NF and:", options: ["It has no partial dependencies", "It has no transitive dependencies", "Every attribute is atomic", "It has more than one candidate key"], answer: 1, explanation: "3NF requires that no non-prime attribute is transitively dependent on the primary key." },
  { topic: "database", question: "A 'Transitive Dependency' is characterized by:", options: ["X -> Y and Y -> Z, where Z is non-prime", "X -> Y, where X is not a key", "A -> B, where A is a part of the key", "X -> X"], answer: 0, explanation: "In 3NF, if X is a PK, then Y depends on X, and Z depends on Y, making Z transitively dependent on X." },
  { topic: "database", question: "Boyce-Codd Normal Form (BCNF) is a stronger version of:", options: ["1NF", "2NF", "3NF", "4NF"], answer: 2, explanation: "BCNF deals with anomalies that 3NF might miss when there are multiple overlapping candidate keys." },
  { topic: "database", question: "For a relation to be in BCNF, for every functional dependency X -> Y:", options: ["Y must be a prime attribute", "X must be a super key", "Y must be a subset of X", "X must be a part of the key"], answer: 1, explanation: "The determinant must be a candidate key." },
  { topic: "database", question: "What is an 'Update Anomaly'?", options: ["When a row cannot be inserted", "When a row is deleted and unrelated information is lost", "When a value is updated in one place but remains old in another due to redundancy", "When the database crashes during an update"], answer: 2, explanation: "Redundancy leads to inconsistent data if not all copies are updated." },
  { topic: "database", question: "A 'Functional Dependency' X -> Y means:", options: ["X is a subset of Y", "For any two tuples t1 and t2, if t1[X] = t2[X], then t1[Y] = t2[Y]", "X and Y are the same", "Y is the primary key"], answer: 1, explanation: "The value of X uniquely determines the value of Y." },
  { topic: "database", question: "Which normal form deals with 'Multivalued Dependencies' (MVD)?", options: ["2NF", "3NF", "4NF", "5NF"], answer: 2, explanation: "4NF is designed to handle MVDs." },
  { topic: "database", question: "Which normal form deals with 'Join Dependencies'?", options: ["3NF", "4NF", "5NF", "BCNF"], answer: 2, explanation: "5NF (Project-Join Normal Form) deals with cases where a relation cannot be decomposed into smaller ones without losing information." },
  { topic: "database", question: "What is 'Lossless Join Decomposition'?", options: ["A decomposition where the original relation can be reconstructed by joining the parts", "A decomposition that saves disk space", "A decomposition that removes all columns", "A decomposition that loses some rows"], answer: 0, explanation: "It ensures no information is lost when a relation is split and rejoined." },
  { topic: "database", question: "What is 'Dependency Preservation'?", options: ["Ensuring all constraints are checked", "Ensuring that all functional dependencies can be checked within the individual decomposed relations", "Keeping the same primary key", "Ensuring the database is always online"], answer: 1, explanation: "It is a desirable property of normalization where constraints can be checked without rejoining tables." },
  { topic: "database", question: "According to Armstrong's Axioms, the 'Reflexivity Rule' states:", options: ["If X -> Y, then XZ -> YZ", "If Y is a subset of X, then X -> Y", "If X -> Y and Y -> Z, then X -> Z", "If X -> Y, then Y -> X"], answer: 1, explanation: "Reflexivity is one of the fundamental rules for inferring FDs." },
  { topic: "database", question: "According to Armstrong's Axioms, the 'Augmentation Rule' states:", options: ["If X -> Y, then XZ -> YZ", "If X -> Y and Y -> Z, then X -> Z", "If X -> Y, then X -> YZ", "If X -> Y, then X -> Z"], answer: 0, explanation: "Adding the same attributes to both sides of an FD preserves the dependency." },
  { topic: "database", question: "According to Armstrong's Axioms, the 'Transitivity Rule' states:", options: ["If X -> Y, then Y -> X", "If X -> Y and Y -> Z, then X -> Z", "If X -> Y, then XZ -> YZ", "If X -> Y, then X -> YZ"], answer: 1, explanation: "Transitivity allows chaining of dependencies." },
  { topic: "database", question: "What is a 'Trivial Functional Dependency'?", options: ["X -> Y where Y is a subset of X", "X -> Y where X is a candidate key", "X -> Y where Y is NULL", "X -> Y which is not useful"], answer: 0, explanation: "It is called trivial because it always holds in any relation." },
  { topic: "database", question: "The 'Closure of a Set of Attributes' X+ is:", options: ["The set of all attributes that are functionally dependent on X", "The set of all attributes in the relation", "The set of all primary keys", "The set of all rows starting with X"], answer: 0, explanation: "X+ is used to determine if X is a candidate key." },
  { topic: "database", question: "If attribute A determines B, and B determines C, then A determines C. This is called:", options: ["Reflexivity", "Augmentation", "Transitivity", "Decomposition"], answer: 2, explanation: "This is a direct application of the Transitivity axiom." },
  { topic: "database", question: "A relation with only two attributes is always in:", options: ["3NF", "BCNF", "4NF", "5NF"], answer: 1, explanation: "Binary relations (two columns) are automatically in BCNF." },
  { topic: "database", question: "Normalization is usually done during the ________ phase of database design.", options: ["Physical", "Logical", "Conceptual", "Implementation"], answer: 1, explanation: "Normalization refines the relational schema (logical design)." },
  { topic: "database", question: "What is 'Denormalization'?", options: ["The process of moving from 1NF to 3NF", "Intentionally introducing redundancy to improve read performance", "Fixing errors in a database", "Converting a NoSQL database to SQL"], answer: 1, explanation: "Denormalization reduces the number of joins needed for queries at the cost of redundancy." },
  { topic: "database", question: "A 'Canonical Cover' of a set of FDs is:", options: ["A minimal set of FDs that is equivalent to the original set", "A set of FDs that contains all possible dependencies", "The primary key of the relation", "A way to hide sensitive data"], answer: 0, explanation: "Canonical cover (minimal cover) has no redundant FDs or attributes." },
  { topic: "database", question: "In 3NF, a non-prime attribute cannot be determined by:", options: ["A candidate key", "Another non-prime attribute", "A super key", "The whole primary key"], answer: 1, explanation: "Dependency on another non-prime attribute would be a transitive dependency." },
  { topic: "database", question: "Which anomaly occurs when we cannot represent a fact without inserting another unrelated fact?", options: ["Insertion Anomaly", "Deletion Anomaly", "Update Anomaly", "Selection Anomaly"], answer: 0, explanation: "E.g., you can't add a new course if no student has enrolled yet." },
  { topic: "database", question: "Which anomaly occurs when deleting a row results in the loss of data that was intended to be kept?", options: ["Insertion Anomaly", "Deletion Anomaly", "Update Anomaly", "Modification Anomaly"], answer: 1, explanation: "E.g., deleting the last student in a course also deletes the course info." },
  { topic: "database", question: "A 'Prime Attribute' is an attribute that:", options: ["Is the first column", "Is part of at least one candidate key", "Cannot be NULL", "Is of type INT"], answer: 1, explanation: "All other attributes are non-prime." },
  { topic: "database", question: "What is the 'Closure of a set of FDs' F+?", options: ["The set of all FDs that can be logically inferred from F", "The set of all attributes", "The set of all primary keys", "The set of all tables"], answer: 0, explanation: "F+ contains all dependencies that are implied by the set F." },
  { topic: "database", question: "Multivalued Dependency (MVD) X ->> Y holds if:", options: ["X determines multiple values of Y independently of other attributes", "X is a part of Y", "Y is a subset of X", "X is a unique key"], answer: 0, explanation: "MVD occurs when one attribute implies a set of values for another." },
  { topic: "database", question: "Which of the following is true about BCNF?", options: ["It is always dependency-preserving", "It is not always dependency-preserving", "It is weaker than 3NF", "It allows transitive dependencies"], answer: 1, explanation: "Some 3NF relations can be decomposed into BCNF only by losing some functional dependencies." },
  { topic: "database", question: "A relation is in 1NF if:", options: ["It has a primary key", "All domains are atomic", "There are no duplicate rows", "All of the above"], answer: 3, explanation: "1NF requires atomicity, uniqueness of rows, and a PK (implicitly)." },
  { topic: "database", question: "The rule 'If X -> Y and X -> Z then X -> YZ' is called:", options: ["Union Rule", "Decomposition Rule", "Pseudo-transitivity", "Augmentation"], answer: 0, explanation: "This is the Union rule of FDs." },
  { topic: "database", question: "The rule 'If X -> YZ then X -> Y and X -> Z' is called:", options: ["Union Rule", "Decomposition Rule", "Augmentation", "Reflexivity"], answer: 1, explanation: "This is the Decomposition rule (splitting the right side)." },
  { topic: "database", question: "A 'Trivial' multivalued dependency X ->> Y holds if:", options: ["Y is a subset of X or X U Y = R", "Y is the primary key", "X is empty", "None of the above"], answer: 0, explanation: "Trivial MVDs always hold." },
  { topic: "database", question: "When is a decomposition 'Lossy'?", options: ["When joining the sub-relations produces more rows than the original relation", "When data is deleted during decomposition", "When the table names are changed", "When the primary key is lost"], answer: 0, explanation: "Joining back produces 'spurious tuples' that weren't in the original data." },
  { topic: "database", question: "What is the criteria for a decomposition of R into R1 and R2 to be lossless?", options: ["R1 ∩ R2 must be a super key for R1 or R2", "R1 and R2 must have the same number of rows", "R1 ∪ R2 must be empty", "R1 must have more rows than R2"], answer: 0, explanation: "The common attributes must uniquely identify rows in at least one of the relations." },
  { topic: "database", question: "Which normal form is concerned with the 'Project-Join' property?", options: ["2NF", "3NF", "BCNF", "5NF"], answer: 3, explanation: "5NF ensures a relation can be reconstructed from its projections." },
  { topic: "database", question: "If a relation has no composite candidate keys, it is automatically in:", options: ["2NF", "3NF", "BCNF", "4NF"], answer: 0, explanation: "Partial dependency can only exist if the key is composite." },
  { topic: "database", question: "The 'Primary Key' is used as the ________ for 2NF and 3NF checks.", options: ["Determinant", "Reference point", "Foreign key", "Index"], answer: 1, explanation: "Normal forms are defined relative to candidate/primary keys." },
  { topic: "database", question: "Normalization helps in:", options: ["Increasing query performance", "Reducing storage space", "Maintaining data integrity", "Both B and C"], answer: 3, explanation: "It reduces space by removing duplicates and maintains integrity by preventing anomalies." },

  // 6. ER Model (30 Qs)
  { topic: "database", question: "In an ER diagram, an 'Entity' is represented by a:", options: ["Ellipse", "Rectangle", "Diamond", "Line"], answer: 1, explanation: "Rectangles represent entity sets." },
  { topic: "database", question: "In an ER diagram, an 'Attribute' is represented by a:", options: ["Rectangle", "Ellipse", "Diamond", "Triangle"], answer: 1, explanation: "Ellipses represent attributes." },
  { topic: "database", question: "In an ER diagram, a 'Relationship' is represented by a:", options: ["Rectangle", "Ellipse", "Diamond", "Double Ellipse"], answer: 2, explanation: "Diamonds represent relationship sets." },
  { topic: "database", question: "A 'Multivalued Attribute' is represented by a:", options: ["Dashed Ellipse", "Double Ellipse", "Underlined Ellipse", "Rectangle"], answer: 1, explanation: "Double ellipses indicate attributes that can have multiple values (e.g., phone numbers)." },
  { topic: "database", question: "A 'Derived Attribute' is represented by a:", options: ["Dashed Ellipse", "Double Ellipse", "Rectangle", "Diamond"], answer: 0, explanation: "Dashed ellipses represent attributes calculated from others (e.g., Age from DOB)." },
  { topic: "database", question: "What is a 'Weak Entity Set'?", options: ["An entity set that has no primary key of its own", "An entity set with very few attributes", "An entity set that is not used in queries", "An entity set that contains NULL values"], answer: 0, explanation: "It depends on a strong entity set for identification." },
  { topic: "database", question: "A 'Weak Entity Set' is represented by a:", options: ["Double Rectangle", "Double Diamond", "Double Ellipse", "Dashed Rectangle"], answer: 0, explanation: "The identifying relationship is represented by a double diamond." },
  { topic: "database", question: "The 'Cardinality Ratio' 1:N means:", options: ["One entity in A is associated with any number of entities in B", "One entity in B is associated with exactly one entity in A", "Both A and B", "None of the above"], answer: 2, explanation: "It defines the maximum number of relationship instances an entity can participate in." },
  { topic: "database", question: "What is 'Total Participation' in a relationship?", options: ["Every entity in the entity set must participate in at least one relationship", "Only some entities participate", "The relationship is optional", "The entity set is a primary key"], answer: 0, explanation: "Total participation is represented by a double line in ER diagrams." },
  { topic: "database", question: "A 'Composite Attribute' is an attribute that:", options: ["Can be divided into smaller sub-parts", "Can have multiple values", "Is calculated from other attributes", "Is a primary key"], answer: 0, explanation: "E.g., 'Name' can be split into First Name and Last Name." },
  { topic: "database", question: "What is a 'Recursive Relationship'?", options: ["A relationship between two different tables", "A relationship where the same entity set participates more than once in different roles", "A relationship that is defined using a subquery", "A relationship with no attributes"], answer: 1, explanation: "E.g., Employee 'manages' Employee." },
  { topic: "database", question: "The 'Degree' of a relationship set is:", options: ["The number of entities in the set", "The number of participating entity sets", "The number of attributes in the relationship", "The number of primary keys"], answer: 1, explanation: "Binary relationships have degree 2; Ternary have degree 3." },
  { topic: "database", question: "In an ER diagram, the primary key of an entity set is indicated by:", options: ["Bold text", "Underlining the attribute name", "Italic text", "Asterisk"], answer: 1, explanation: "Underlining denotes the key attribute." },
  { topic: "database", question: "Which of the following is NOT a level of mapping in ER to Relational conversion?", options: ["Entity set to Table", "Relationship set to Table", "Multivalued attribute to Table", "Primary key to Table"], answer: 3, explanation: "PK is a column in a table, not a separate table itself." },
  { topic: "database", question: "A 'Partial Key' is used to identify:", options: ["A strong entity", "A weak entity (in combination with the owner's key)", "A composite attribute", "A relationship"], answer: 1, explanation: "The partial key (or discriminator) of a weak entity is underlined with a dashed line." },
  { topic: "database", question: "The process of designating subgroupings within an entity set is called:", options: ["Generalization", "Specialization", "Aggregation", "Categorization"], answer: 1, explanation: "Specialization is a top-down design process." },
  { topic: "database", question: "The process of taking two or more entity sets and combining them into a higher-level entity set is:", options: ["Specialization", "Generalization", "Aggregation", "Normalization"], answer: 1, explanation: "Generalization is a bottom-up design process." },
  { topic: "database", question: "What is 'Aggregation' in ER modeling?", options: ["Summing up values", "A relationship between a relationship and an entity set", "Combining multiple tables into one", "A type of normalization"], answer: 1, explanation: "Aggregation allows us to treat a relationship as an abstract entity." },
  { topic: "database", question: "A '1:1' relationship between A and B can be mapped to the relational model by:", options: ["Adding a foreign key in A pointing to B", "Adding a foreign key in B pointing to A", "Merging both tables if participation is total", "All of the above"], answer: 3, explanation: "Depending on participation constraints, multiple mapping strategies exist." },
  { topic: "database", question: "An 'M:N' relationship is mapped to the relational model by:", options: ["Adding a foreign key in one of the tables", "Creating a new cross-reference table with PKs of both entities", "Adding a multivalued attribute", "It cannot be mapped"], answer: 1, explanation: "Many-to-many relationships always require a separate bridge/junction table." },
  { topic: "database", question: "What is an 'Identifying Relationship'?", options: ["A relationship that links a weak entity to its owner", "A relationship with a unique name", "A relationship between two primary keys", "A relationship used for authentication"], answer: 0, explanation: "It is represented by a double diamond." },
  { topic: "database", question: "Which constraint ensures that an entity can belong to at most one lower-level entity set in a specialization?", options: ["Overlap constraint", "Disjoint constraint", "Total constraint", "Partial constraint"], answer: 1, explanation: "Disjointness means an entity cannot be more than one specialized type." },
  { topic: "database", question: "Which constraint specifies whether an entity in the higher-level set must belong to at least one lower-level set?", options: ["Disjointness", "Completeness (Total/Partial)", "Cardinality", "Integrity"], answer: 1, explanation: "Total completeness means every superclass entity must be in a subclass." },
  { topic: "database", question: "A 'Complex Attribute' is formed by nesting:", options: ["Multivalued and composite attributes", "Simple and derived attributes", "Primary and foreign keys", "Tables and views"], answer: 0, explanation: "E.g., a composite attribute where one part is multivalued." },
  { topic: "database", question: "In the 'Enhanced ER' (EER) model, 'Subclasses' and 'Superclasses' are used for:", options: ["Inheritance", "Normalization", "Concurrency", "Indexing"], answer: 0, explanation: "Subclasses inherit attributes and relationships from their superclass." },
  { topic: "database", question: "What is a 'Ternary' relationship?", options: ["A relationship involving two entities", "A relationship involving three entities", "A relationship with three attributes", "A relationship that repeats three times"], answer: 1, explanation: "Degree of relationship is 3." },
  { topic: "database", question: "A 'Discriminator' is:", options: ["Another name for primary key", "The partial key of a weak entity set", "A type of database user", "An SQL operator"], answer: 1, explanation: "It distinguishes among all entities of a weak set that depend on the same strong entity." },
  { topic: "database", question: "The 'ISA' relationship in ER diagrams represents:", options: ["Inheritance / Specialization", "Association", "Aggregation", "Equality"], answer: 0, explanation: "ISA (is-a) links a subclass to a superclass." },
  { topic: "database", question: "Which of the following is an example of an entity?", options: ["Color", "Price", "A specific student", "A primary key"], answer: 2, explanation: "An entity is a 'thing' or 'object' in the real world that is distinguishable from other objects." },
  { topic: "database", question: "ER diagrams are primarily used for ________ design.", options: ["Physical", "Conceptual", "Internal", "Logical"], answer: 1, explanation: "ER model is the most popular tool for conceptual database design." },

  // 7. Transaction & Concurrency (30 Qs)
  { topic: "database", question: "What does the 'A' in ACID stand for?", options: ["Availability", "Atomicity", "Authority", "Aggregation"], answer: 1, explanation: "Atomicity ensures that either all operations of a transaction are reflected in the database, or none are." },
  { topic: "database", question: "What does the 'I' in ACID stand for?", options: ["Information", "Integrity", "Isolation", "Indexing"], answer: 2, explanation: "Isolation ensures that concurrent transactions do not interfere with each other." },
  { topic: "database", question: "The property that ensures the database remains in a valid state after a transaction is:", options: ["Atomicity", "Consistency", "Isolation", "Durability"], answer: 1, explanation: "Consistency ensures that a transaction transforms the DB from one valid state to another." },
  { topic: "database", question: "The property that ensures changes are permanent even after a system crash is:", options: ["Atomicity", "Consistency", "Isolation", "Durability"], answer: 3, explanation: "Durability guarantees that committed data is saved in non-volatile memory." },
  { topic: "database", question: "Which transaction state is reached after the final statement has been executed?", options: ["Active", "Partially Committed", "Committed", "Aborted"], answer: 1, explanation: "Partially Committed is the state after the last statement but before the actual 'commit' process finishes." },
  { topic: "database", question: "A transaction that fails is moved to the ________ state.", options: ["Terminated", "Failed", "Aborted", "Rolled-back"], answer: 1, explanation: "After failing, it is then aborted and the database is rolled back." },
  { topic: "database", question: "What is a 'Schedule' in the context of transactions?", options: ["A time table for backups", "A sequence of operations from one or more transactions", "A list of users", "A set of SQL queries"], answer: 1, explanation: "A schedule determines the order in which instructions of concurrent transactions are executed." },
  { topic: "database", question: "A schedule is 'Serial' if:", options: ["Transactions are executed one after another", "Transactions are interleaved", "Transactions run in parallel on different CPUs", "Transactions are executed in reverse order"], answer: 0, explanation: "In a serial schedule, only one transaction runs at a time." },
  { topic: "database", question: "What is 'Conflict Serializability'?", options: ["A schedule that is equivalent to some serial schedule by swapping non-conflicting operations", "A schedule that has no conflicts", "A schedule that runs without locks", "A schedule that is always fast"], answer: 0, explanation: "Conflict equivalence is checked to ensure consistent results." },
  { topic: "database", question: "Two operations conflict if they belong to different transactions, access the same data item, and:", options: ["Both are Reads", "At least one is a Write", "Both are Writes", "Either B or C"], answer: 3, explanation: "Read-Read operations do not conflict." },
  { topic: "database", question: "What is 'Deadlock'?", options: ["When the database is disconnected", "When two or more transactions are waiting for each other to release locks", "When a transaction takes too long to finish", "When data is corrupted"], answer: 1, explanation: "Deadlock is a cycle of dependency where no transaction can proceed." },
  { topic: "database", question: "The 'Two-Phase Locking' (2PL) protocol ensures:", options: ["Deadlock freedom", "Conflict Serializability", "View Serializability", "Faster execution"], answer: 1, explanation: "2PL guarantees conflict serializable schedules but not deadlock freedom." },
  { topic: "database", question: "In 2PL, the 'Growing Phase' is when a transaction:", options: ["Releases all locks", "Can only obtain locks but not release any", "Can both obtain and release locks", "Increases its priority"], answer: 1, explanation: "In the growing phase, the transaction acquires all needed locks." },
  { topic: "database", question: "In 2PL, the 'Shrinking Phase' is when a transaction:", options: ["Obtains new locks", "Releases locks but cannot obtain new ones", "Is aborted", "Deletes data"], answer: 1, explanation: "Once a lock is released, no more locks can be requested." },
  { topic: "database", question: "Which locking level provides the highest concurrency?", options: ["Database-level", "Table-level", "Page-level", "Row-level"], answer: 3, explanation: "Fine-grained locking (row-level) allows more users to work on the same table simultaneously." },
  { topic: "database", question: "What is a 'Shared Lock' (S-lock)?", options: ["A lock that allows other transactions to Read but not Write", "A lock that prevents all access", "A lock used for backups", "A lock that allows multiple Writes"], answer: 0, explanation: "Multiple S-locks can be held on the same item simultaneously." },
  { topic: "database", question: "What is an 'Exclusive Lock' (X-lock)?", options: ["Allows both Read and Write by the holder, but no access to others", "Allows others to Read", "Only used for Primary Keys", "A lock that never expires"], answer: 0, explanation: "Only one X-lock can exist on a data item at a time." },
  { topic: "database", question: "A 'Dirty Read' occurs when:", options: ["A transaction reads data that has been modified by another uncommitted transaction", "A transaction reads the same data twice and gets different results", "A transaction reads old data from a backup", "A transaction cannot read any data"], answer: 0, explanation: "If the first transaction rolls back, the second one has read 'dirty' data." },
  { topic: "database", question: "A 'Non-repeatable Read' occurs when:", options: ["A transaction reads a row, and another transaction modifies it before the first one finishes", "A transaction reads a row twice and it disappears", "A transaction cannot commit", "The database crashes"], answer: 0, explanation: "Re-reading the same row within the same transaction yields different data." },
  { topic: "database", question: "What is a 'Phantom Read'?", options: ["A transaction reads a set of rows, and another transaction inserts/deletes rows in that range", "The data looks like it's there but it's not", "A read operation on a deleted table", "An error during a join"], answer: 0, explanation: "New rows appearing (or disappearing) in a range query." },
  { topic: "database", question: "Which isolation level prevents Dirty Reads but allows Non-repeatable Reads?", options: ["Read Uncommitted", "Read Committed", "Repeatable Read", "Serializable"], answer: 1, explanation: "Read Committed ensures that only committed data is read." },
  { topic: "database", question: "Which isolation level is the highest and prevents all anomalies?", options: ["Read Committed", "Repeatable Read", "Snapshot Isolation", "Serializable"], answer: 3, explanation: "Serializable ensures the schedule is equivalent to a serial execution." },
  { topic: "database", question: "What is 'Cascading Rollback'?", options: ["A single rollback that takes a long time", "When the failure of one transaction leads to the rollback of several others", "A rollback of the entire database server", "A rollback that cannot be stopped"], answer: 1, explanation: "Occurs when transactions read data from uncommitted transactions that later fail." },
  { topic: "database", question: "The 'Strict 2PL' protocol prevents:", options: ["Deadlocks", "Cascading Rollbacks", "Dirty Reads", "Both B and C"], answer: 3, explanation: "Strict 2PL holds exclusive locks until commit/abort, preventing others from reading uncommitted data." },
  { topic: "database", question: "The 'Wait-Die' and 'Wound-Wait' schemes are used for:", options: ["Concurrency control", "Deadlock prevention", "Deadlock detection", "Query optimization"], answer: 1, explanation: "These schemes use timestamps to prevent cycles." },
  { topic: "database", question: "A 'Log' file in DBMS is used for:", options: ["Storing user names", "Recording all database modifications for recovery", "Listing all SQL queries for performance analysis", "Storing the database schema"], answer: 1, explanation: "The log (write-ahead log) is essential for recovering from crashes." },
  { topic: "database", question: "What is 'Checkpointing' in recovery?", options: ["A periodic point where all buffers are flushed to disk and a record is added to the log", "A backup of the entire database", "Checking the database for viruses", "A way to pause all transactions"], answer: 0, explanation: "Checkpoints reduce the time needed for recovery after a crash." },
  { topic: "database", question: "The 'Timestamp Ordering' protocol ensures serializability by:", options: ["Using locks", "Assigning a unique timestamp to each transaction and ensuring order", "Executing transactions in alphabetical order", "Randomly selecting the next transaction"], answer: 1, explanation: "No locks are used; conflicts are resolved by comparing timestamps." },
  { topic: "database", question: "What is 'Optimistic Concurrency Control'?", options: ["Assuming that conflicts are rare and checking for them only at commit time", "Assuming that the database will never crash", "Using very few locks", "A protocol that always succeeds"], answer: 0, explanation: "Used in environments with low contention to improve performance." },
  { topic: "database", question: "In transaction management, what is a 'Blind Write'?", options: ["Writing data without reading it first", "Writing to a non-existent table", "Writing data with eyes closed", "An automated write operation"], answer: 0, explanation: "Blind writes are significant in View Serializability." },

  // 8. Indexing & Views (20 Qs)
  { topic: "database", question: "What is the primary reason for creating an index in a database?", options: ["To save disk space", "To speed up data retrieval", "To ensure data security", "To simplify the database schema"], answer: 1, explanation: "Indexes allow the DBMS to find rows faster without scanning the whole table." },
  { topic: "database", question: "Which data structure is most commonly used for indexing in relational databases?", options: ["Hash Table", "B+ Tree", "Linked List", "Binary Search Tree"], answer: 1, explanation: "B+ trees are efficient for both equality and range queries." },
  { topic: "database", question: "A 'Clustered Index' is one where:", options: ["Multiple columns are indexed together", "The physical order of data in the table is the same as the order of the index", "The index is stored in a separate cluster", "Many users share the index"], answer: 1, explanation: "A table can have only one clustered index (usually the PK)." },
  { topic: "database", question: "A 'Non-Clustered Index' contains:", options: ["The actual data rows", "Pointers (addresses) to the actual data rows", "A copy of the whole table", "Only NULL values"], answer: 1, explanation: "The leaf nodes of non-clustered indexes contain row locators." },
  { topic: "database", question: "What is a 'Composite Index'?", options: ["An index on a single column", "An index on two or more columns", "An index that is part of a view", "An index that uses different data structures"], answer: 1, explanation: "Useful for queries that filter on multiple fields." },
  { topic: "database", question: "A 'View' in SQL is:", options: ["A physical table that stores results", "A virtual table based on the result-set of an SQL statement", "A graphical representation of the schema", "A backup of a table"], answer: 1, explanation: "Views do not store data physically; they are dynamically generated." },
  { topic: "database", question: "What is a 'Materialized View'?", options: ["A view that is deleted after use", "A view whose results are physically stored on disk and periodically updated", "A view that contains only text data", "A view that is used for encryption"], answer: 1, explanation: "Used in data warehousing to speed up complex aggregations." },
  { topic: "database", question: "Which command is used to create a view?", options: ["MAKE VIEW", "NEW VIEW", "CREATE VIEW", "DEFINE VIEW"], answer: 2, explanation: "Standard SQL command is CREATE VIEW." },
  { topic: "database", question: "A 'Secondary Index' in a DBMS is:", options: ["An index on a non-ordering field", "The second index created on a table", "An index that is only used if the first one fails", "A backup index"], answer: 0, explanation: "It provides an alternative access path to data." },
  { topic: "database", question: "What is 'Dense Indexing'?", options: ["An index record exists for every search-key value in the file", "An index record exists for only some values", "An index that takes up a lot of space", "An index on a very large table"], answer: 0, explanation: "Contrast with Sparse Indexing." },
  { topic: "database", question: "What is 'Sparse Indexing'?", options: ["An index record exists for every row", "Index records are created only for some values (e.g., one for each block)", "An index that is rarely used", "An index with many NULLs"], answer: 1, explanation: "Sparse indexes take less space but might be slightly slower than dense ones." },
  { topic: "database", question: "The 'Hashing' technique is best for:", options: ["Range queries (e.g., WHERE age > 20)", "Exact match queries (e.g., WHERE id = 101)", "Sorting data", "Finding the minimum value"], answer: 1, explanation: "Hash indexes provide O(1) time for equality lookups but don't support ranges." },
  { topic: "database", question: "A 'Unique Index' ensures:", options: ["That the table has a unique name", "That no two rows have the same value in the indexed columns", "That only one user can access the index", "That the index is stored on a unique drive"], answer: 1, explanation: "It enforces uniqueness constraints." },
  { topic: "database", question: "What is a 'Covering Index'?", options: ["An index that covers all tables in the database", "An index that contains all the columns needed for a specific query", "An index that is visible to all users", "A primary key"], answer: 1, explanation: "A query can be satisfied entirely from the index without reading the table (Index-Only Scan)." },
  { topic: "database", question: "What are 'Stored Procedures'?", options: ["SQL queries stored in a text file", "Precompiled collections of SQL statements and logic stored in the database", "Instructions for the DBA", "Temporary tables"], answer: 1, explanation: "Procedures improve performance and security by reducing network traffic and abstracting logic." },
  { topic: "database", question: "What is a 'Trigger'?", options: ["A button in the UI", "A procedure that is automatically executed in response to certain events (INSERT, UPDATE, DELETE)", "A way to start the database", "An error message"], answer: 1, explanation: "Triggers help maintain integrity and automate tasks." },
  { topic: "database", question: "What is a 'Cursor' in SQL?", options: ["The mouse pointer", "A database object that allows row-by-row processing of a result set", "A way to delete all data", "A specialized index"], answer: 1, explanation: "Cursors are used in stored procedures to iterate through query results." },
  { topic: "database", question: "Which of the following is an advantage of using Views?", options: ["Enhanced Security by hiding columns", "Reduced complexity for users", "Data Independence", "All of the above"], answer: 3, explanation: "Views provide a layer of abstraction." },
  { topic: "database", question: "In a B+ Tree, data pointers are stored only in:", options: ["Root node", "Internal nodes", "Leaf nodes", "All nodes"], answer: 2, explanation: "B+ trees store actual data/pointers in the leaves, while internal nodes only store keys for navigation." },
  { topic: "database", question: "Which command is used to remove an index?", options: ["DELETE INDEX", "REMOVE INDEX", "DROP INDEX", "RENAME INDEX"], answer: 2, explanation: "DROP INDEX index_name is the syntax." },

  // 9. Constraints & Integrity (20 Qs)
  { topic: "database", question: "Which constraint prevents duplicate values in a column but allows NULLs?", options: ["PRIMARY KEY", "UNIQUE", "NOT NULL", "CHECK"], answer: 1, explanation: "Unlike PK, the UNIQUE constraint allows one or more NULL values (depending on the DBMS)." },
  { topic: "database", question: "Which constraint ensures that a column cannot have an empty value?", options: ["NOT NULL", "UNIQUE", "DEFAULT", "CHECK"], answer: 0, explanation: "NOT NULL forces a field to always contain a value." },
  { topic: "database", question: "What is a 'CHECK' constraint?", options: ["A way to check if a user is logged in", "A constraint that limits the range of values that can be placed in a column", "A backup check", "A way to count records"], answer: 1, explanation: "E.g., CHECK (Price > 0)." },
  { topic: "database", question: "The 'DEFAULT' constraint is used to:", options: ["Set a default value for a column if no value is specified", "Create a primary key", "Encrypt data by default", "Delete data automatically"], answer: 0, explanation: "If no value is provided during INSERT, the default is used." },
  { topic: "database", question: "Which constraint is a combination of 'NOT NULL' and 'UNIQUE'?", options: ["FOREIGN KEY", "PRIMARY KEY", "CHECK", "ASSERTION"], answer: 1, explanation: "A primary key must be unique and cannot be null." },
  { topic: "database", question: "The 'FOREIGN KEY' constraint is used to enforce:", options: ["Entity Integrity", "Referential Integrity", "Domain Integrity", "User Integrity"], answer: 1, explanation: "It ensures the child table matches the parent table." },
  { topic: "database", question: "What does 'ON DELETE CASCADE' mean?", options: ["The deletion is canceled if there are related rows", "If a row in the parent table is deleted, related rows in the child table are also deleted", "The child rows are set to NULL", "The database is deleted"], answer: 1, explanation: "It automates the cleanup of related data." },
  { topic: "database", question: "What does 'ON DELETE SET NULL' mean?", options: ["Delete the child rows", "Set the foreign key column in the child table to NULL when the parent row is deleted", "Do nothing", "Raise an error"], answer: 1, explanation: "The relationship is broken by nulling the reference." },
  { topic: "database", question: "A 'Domain Constraint' specifies:", options: ["The name of the database", "The set of allowed values for an attribute (data type, range, etc.)", "The list of users", "The table owner"], answer: 1, explanation: "It is the simplest form of integrity constraint." },
  { topic: "database", question: "What is an 'Assertion' in SQL?", options: ["A simple CHECK constraint", "A predicate expressing a condition that the database must always satisfy", "A type of trigger", "An error message"], answer: 1, explanation: "Assertions can involve multiple tables (rarely supported by common DBMS)." },
  { topic: "database", question: "Integrity constraints are enforced by:", options: ["The user application", "The DBMS", "The operating system", "The hardware"], answer: 1, explanation: "Centralized enforcement in the DBMS ensures data consistency across all apps." },
  { topic: "database", question: "Which keyword is used to name a constraint in a CREATE TABLE statement?", options: ["NAME", "CONSTRAINT", "IDENTIFIER", "LABEL"], answer: 1, explanation: "E.g., CONSTRAINT pk_emp PRIMARY KEY (id)." },
  { topic: "database", question: "Can a table have multiple FOREIGN KEY constraints?", options: ["Yes", "No", "Only if they point to the same table", "Only two"], answer: 0, explanation: "A table can have many foreign keys referencing different tables." },
  { topic: "database", question: "Can a table have multiple PRIMARY KEY constraints?", options: ["Yes", "No", "Only if it is a composite key", "Only in MySQL"], answer: 1, explanation: "A table can have only one primary key (though it can be composite)." },
  { topic: "database", question: "What is 'Domain Integrity'?", options: ["Checking if the domain name is valid", "Ensuring that all data in a column is within the defined domain", "Protecting the database from hackers", "Using unique keys"], answer: 1, explanation: "Includes data types, lengths, and CHECK constraints." },
  { topic: "database", question: "The 'RESTRICT' option in ON DELETE means:", options: ["Delete all rows", "Prevent the deletion of the parent row if child rows exist", "Set to default", "Ignore the error"], answer: 1, explanation: "It is the default behavior in many systems to prevent broken links." },
  { topic: "database", question: "Which constraint is checked whenever a row is inserted or modified?", options: ["NOT NULL", "CHECK", "UNIQUE", "All of the above"], answer: 3, explanation: "All constraints must be satisfied for an operation to succeed." },
  { topic: "database", question: "Which SQL command can be used to add a constraint to an existing table?", options: ["UPDATE TABLE", "ALTER TABLE ADD CONSTRAINT", "MODIFY TABLE", "SET CONSTRAINT"], answer: 1, explanation: "ALTER TABLE is used for schema changes." },
  { topic: "database", question: "A 'Candidate Key' that is not chosen as the Primary Key is called a:", options: ["Alternate Key", "Secondary Key", "Foreign Key", "Back-up Key"], answer: 0, explanation: "Alternate keys are also unique identifiers." },
  { topic: "database", question: "Which integrity rule states that 'No component of a primary key can be null'?", options: ["Referential Integrity", "Entity Integrity", "Domain Integrity", "Relational Integrity"], answer: 1, explanation: "Entity integrity ensures every row can be uniquely identified." }
];